module top_module(
    input signed [15:0] obf_a,
    input signed [15:0] b,
    input sub,
    output reg signed [15:0] result,
    output reg overflow
);always @(*) begin
        if (sub) begin
            result = obf_a - b;
            overflow = ((obf_a < 0) & (b > 0) & (result > 0)) | ((obf_a > 0) & (b < 0) & (result < 0));
        end else begin
            result = obf_a + b;
            overflow = ((obf_a > 0) & (b > 0) & (result < 0)) | ((obf_a < 0) & (b < 0) & (result > 0));
        end
    end

endmodule
